import whiterose from "../assets/whiterose.png.jpeg";
import Royal from "../assets/Royal.png";
import elegant from "../assets/elegent.png";
function WeddingDecoration() {
  const decorations = [
    {
      name: "White Rose Decoration",
      experience: "6 Years",
      service: "Wedding Decoration",
      package:
        "Flower arrangements, stage decoration, table setup, entrance design, and elegant wedding themes.",
      contact: "whiterose@email.com",
      price: "$2000 package",
      image: whiterose,
    },

    {
      name: "Royal Flower Design",
      experience: "8 Years",
      service: "Luxury Wedding Decoration",
      package:
        "Luxury floral decoration, premium wedding stage setup, lighting effects, and customized wedding themes.",
      contact: "royalflower@email.com",
      price: "$3500 package",
      image: Royal,
    },

    {
      name: "Elegant Touch",
      experience: "5 Years",
      service: "Modern Wedding Decoration",
      package:
        "Modern decoration themes, flower coordination, guest table styling, and romantic wedding setups.",
      contact: "eleganttouch@email.com",
      price: "$1800 package",
      image: el,
    },
  ];

  function requestDecoration(name) {
    alert("Your request has been sent to " + name);
  }

  return (
    <section className="page-section">
      <div className="page-header">
        <h1>Wedding Decoration</h1>

        <p>
          Discover professional wedding decoration services for flowers,
          lighting, stage setup, and elegant wedding themes.
        </p>
      </div>

      <section className="cards">
        {decorations.map((decor, index) => (
          <div className="card" key={index}>
            <img
              src={decor.image}
              alt={decor.name}
              className="service-image"
            />

            <h3>{decor.name}</h3>

            <p><strong>Service:</strong> {decor.service}</p>
            <p><strong>Package Includes:</strong> {decor.package}</p>
            <p><strong>Experience:</strong> {decor.experience}</p>
            <p><strong>Email:</strong> {decor.contact}</p>
            <p><strong>Price:</strong> {decor.price}</p>

            <button
              className="request-btn"
              onClick={() => requestDecoration(decor.name)}
            >
              Request Service
            </button>
          </div>
        ))}
      </section>
    </section>
  );
}

export default WeddingDecoration;
